from pydantic import BaseModel, Field
from typing import Optional, Literal
from enum import Enum

class Priority(str, Enum):
    LOW = 'low'
    MEDIUM = 'medium'
    HIGH = 'high'

class TaskExtraction(BaseModel):
    title: str = Field(..., description="The task title")
    priority: Priority
    due_date: Optional[str] = Field(None, description="ISO 8601 date string")
    assignee: str

def extract_task(user_input: str) -> TaskExtraction:
    result = vex.verify(
        fn=lambda: client.chat.completions.create(
            model="gpt-4o",
            response_model=TaskExtraction,
            messages=[
                {"role": "system", "content": "Extract structured task data from the user input."},
                {"role": "user", "content": user_input}
            ]
        ),
        operation="task_extraction",
        schema=TaskExtraction.model_json_schema(),
        tags={"model": "gpt-4o", "response_model": "TaskExtraction"}
    )
    return result

# Usage
task = extract_task("Remind Alice to submit the Q4 report by Friday, high priority")
print(task.model_dump())

import instructor
from instructor.exceptions import InstructorRetryException
from pydantic import ValidationError
from vex_sdk import Vex, FailureType

vex = Vex(api_key="your-vex-api-key", agent_name="instructor-extraction-agent")
client = instructor.patch(openai.OpenAI(), max_retries=3)

def safe_extract(user_input: str, fallback: TaskExtraction = None) -> Optional[TaskExtraction]:
    try:
        result = vex.verify(
            fn=lambda: client.chat.completions.create(
                model="gpt-4o",
                response_model=TaskExtraction,
                messages=[{"role": "user", "content": user_input}]
            ),
            operation="task_extraction"
        )
        return result
    except InstructorRetryException as e:
        vex.record_failure(
            operation="task_extraction",
            failure_type=FailureType.RETRY_EXHAUSTED,
            error=str(e),
            context={
                "attempts": e.n_attempts,
                "last_validation_errors": str(e.last_completion),
                "input_preview": user_input[:200]
            }
        )
        return fallback
    except ValidationError as e:
        vex.record_failure(
            operation="task_extraction",
            failure_type=FailureType.SCHEMA_VALIDATION,
            error=str(e),
            context={"validation_errors": e.errors()}
        )
        return fallback

import Instructor from '@instructor-ai/instructor';
import OpenAI from 'openai';
import { z } from 'zod';
import { Vex, FailureType } from 'vex-sdk';

const vex = new Vex({ apiKey: 'your-vex-api-key', agentName: 'instructor-ts-agent' });

const oai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const client = Instructor({ client: oai, mode: 'TOOLS' });

const TaskSchema = z.object({
  title: z.string(),
  priority: z.enum(['low', 'medium', 'high']),
  dueDate: z.string().optional(),
  assignee: z.string(),
});

type Task = z.infer<typeof TaskSchema>;

async function extractTask(userInput: string): Promise<Task | null> {
  try {
    const result = await vex.verify(
      () => client.chat.completions.create({
        model: 'gpt-4o',
        response_model: { schema: TaskSchema, name: 'Task' },
        max_retries: 3,
        messages: [
          { role: 'system', content: 'Extract structured task data.' },
          { role: 'user', content: userInput },
        ],
      }),
      {
        operation: 'task_extraction',
        tags: { model: 'gpt-4o', responseModel: 'TaskSchema' },
      }
    );
    return result;
  } catch (error) {
    await vex.recordFailure({
      operation: 'task_extraction',
      failureType: FailureType.RETRY_EXHAUSTED,
      error: String(error),
      context: { inputPreview: userInput.slice(0, 200) },
    });
    return null;
  }
}

// Usage
const task = await extractTask('Ask Bob to finalize the budget report by Monday, medium priority');
console.log(task);
